    name_id_policy = ET.SubElement(saml_request, 'samlp:NameIDPolicy', Format='urn:oasis:names:tc:SAML:2.0:nameid-format:persistent')
    
    # Create the RequestedAuthnContext element
    requested_authn_context = ET.SubElement(saml_request, 'samlp:RequestedAuthnContext', Comparison='exact')
    authn_context_class_ref = ET.SubElement(requested_authn_context, 'saml:AuthnContextClassRef')
    authn_context_class_ref.text = 'urn:oasis:names:tc:SAML:2.0:ac:classes:PasswordProtectedTransport'
    
    # Convert the SAML request to a string
    saml_xml = ET.tostring(saml_request, encoding='unicode')
    
    # Encode and POST the SAML request to the Identity Provider
    headers = {
        'Content-Type': 'application/x-www-form-urlencoded',
        'User-Agent': 'SAML SP'
    }
